function SearchBar() {
  const [query, setQuery] = useState('');
  const debouncedQuery = useDebounce(query, 300);
  const { data: suggestions, isLoading } = useQuery({
    queryKey: ['suggestions', debouncedQuery],
    queryFn: () => fetchSuggestions(debouncedQuery),
    enabled: debouncedQuery.length > 2
  });
  return (
    <div className="relative">
      <input type="text" value={query} onChange={e => setQuery(e.target.value)} placeholder="Rechercher..." />
      {suggestions && suggestions.length > 0 && (
        <ul className="absolute bg-white border rounded mt-1 w-full z-10">
          {suggestions.map(s => <li key={s.id} onClick={() => handleSelectSuggestion(s)}>{s.name}</li>)}
        </ul>
      )}
    </div>
  );
}
